// OKLCH ↔ sRGB conversions (Ottosson's canonical matrices)

const SRGB_GAMMA = 2.4;
const SRGB_OFFSET = 0.055;
const SRGB_SLOPE = 12.92;
const SRGB_TRANSITION = 0.04045;
const SRGB_LINEAR_TRANSITION = SRGB_TRANSITION / SRGB_SLOPE;

function srgbToLinear(c: number): number {
    const s = c < 0 ? -1 : 1;
    const a = c * s;
    if (a <= SRGB_LINEAR_TRANSITION) return c / SRGB_SLOPE;
    return s * ((a + SRGB_OFFSET) / (1 + SRGB_OFFSET)) ** SRGB_GAMMA;
}

function linearToSrgb(c: number): number {
    const s = c < 0 ? -1 : 1;
    const a = c * s;
    if (a <= SRGB_LINEAR_TRANSITION) return c * SRGB_SLOPE;
    return s * ((1 + SRGB_OFFSET) * a ** (1 / SRGB_GAMMA) - SRGB_OFFSET);
}

const LMS_TO_SRGB = [
    +4.0767416621, -3.3077115913, +0.2309699292,
    -1.2684380046, +2.6097574011, -0.3413193965,
    -0.0041960863, -0.7034186147, +1.7076147010,
];

const SRGB_TO_LMS = [
    0.4122214708, 0.5363325363, 0.0514459929,
    0.2119034982, 0.6806995451, 0.1073969566,
    0.0883024619, 0.2817188376, 0.6299787005,
];

const LAB_LMS = {
    l: [1.0, +0.3963377774, +0.2158037573],
    m: [1.0, -0.1055613458, -0.0638541728],
    s: [1.0, -0.0894841775, -1.2914855480],
};

export function clamp(v: number, lo: number, hi: number): number {
    return Math.min(Math.max(v, lo), hi);
}

export function srgbToOKLab(r: number, g: number, b: number): [number, number, number] {
    const rl = srgbToLinear(r), gl = srgbToLinear(g), bl = srgbToLinear(b);
    const l_ = Math.cbrt(SRGB_TO_LMS[0] * rl + SRGB_TO_LMS[1] * gl + SRGB_TO_LMS[2] * bl);
    const m_ = Math.cbrt(SRGB_TO_LMS[3] * rl + SRGB_TO_LMS[4] * gl + SRGB_TO_LMS[5] * bl);
    const s_ = Math.cbrt(SRGB_TO_LMS[6] * rl + SRGB_TO_LMS[7] * gl + SRGB_TO_LMS[8] * bl);
    return [
        0.2104542553 * l_ + 0.7936177850 * m_ - 0.0040720468 * s_,
        1.9779984951 * l_ - 2.4285922050 * m_ + 0.4505937099 * s_,
        0.0259040371 * l_ + 0.7827717662 * m_ - 0.8086757660 * s_,
    ];
}

export function oklabToRgb255(L: number, a: number, b: number): [number, number, number] {
    const l_ = L + LAB_LMS.l[1] * a + LAB_LMS.l[2] * b;
    const m_ = L + LAB_LMS.m[1] * a + LAB_LMS.m[2] * b;
    const s_ = L + LAB_LMS.s[1] * a + LAB_LMS.s[2] * b;
    const l = l_ ** 3, m = m_ ** 3, s = s_ ** 3;
    return [
        Math.round(clamp(linearToSrgb(LMS_TO_SRGB[0] * l + LMS_TO_SRGB[1] * m + LMS_TO_SRGB[2] * s), 0, 1) * 255),
        Math.round(clamp(linearToSrgb(LMS_TO_SRGB[3] * l + LMS_TO_SRGB[4] * m + LMS_TO_SRGB[5] * s), 0, 1) * 255),
        Math.round(clamp(linearToSrgb(LMS_TO_SRGB[6] * l + LMS_TO_SRGB[7] * m + LMS_TO_SRGB[8] * s), 0, 1) * 255),
    ];
}

export function oklabToOklch(L: number, a: number, b: number): [number, number, number] {
    const C = Math.sqrt(a * a + b * b);
    let H = Math.atan2(b, a) * (180 / Math.PI);
    if (H < 0) H += 360;
    return [L, C, H];
}

export function oklchToOklab(L: number, C: number, H: number): [number, number, number] {
    const h = (H * Math.PI) / 180;
    return [L, C * Math.cos(h), C * Math.sin(h)];
}

export function rgbToOklch(r: number, g: number, b: number): [number, number, number] {
    const [L, a, b_] = srgbToOKLab(r / 255, g / 255, b / 255);
    return oklabToOklch(L, a, b_);
}

export function oklchToRgb(L: number, C: number, H: number): [number, number, number] {
    const [la, a, b] = oklchToOklab(L, C, H);
    return oklabToRgb255(la, a, b);
}
